-- ==========================================================
-- GUILDS COMERCIAL — SEED DATA (v2 multi-tenant)
-- Cria org "Guilds" + membros + popula 45 leads (3 demo + 42 reais)
-- Requer: profiles já populada (pós criação dos 4 users no Auth).
-- ==========================================================

-- ==========================================================
-- Passo 1: cria a organização "Guilds", membros e home_org
--          + liga temporariamente o default organizacao_id
-- ==========================================================
do $$
declare
  uid_org      uuid;
  uid_gustavo  uuid := (select id from public.profiles where email = 'gustavog.macedo16@gmail.com' limit 1);
  uid_comerc   uuid := (select id from public.profiles where email = 'comercial@guilds.com.br'     limit 1);
  uid_sdr1     uuid := (select id from public.profiles where email = 'sdr1@guilds.com.br'          limit 1);
  uid_sdr2     uuid := (select id from public.profiles where email = 'sdr2@guilds.com.br'          limit 1);
begin
  if uid_gustavo is null then
    raise exception
      'profiles ainda não populada — crie os 4 usuários e rode o INSERT de profiles antes do seed.';
  end if;

  values ('Guilds', 'guilds', uid_gustavo)
  returning id into uid_org;

  values (uid_org);

  on conflict (organizacao_id, profile_id) do nothing;

  update public.profiles
     set home_organizacao_id = uid_org
   where id in (uid_gustavo, uid_comerc, uid_sdr1, uid_sdr2);

  -- default temporário para os inserts subsequentes (removido no final)
  execute format('alter table public.leads        alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.raio_x       alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.cadencia     alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.newsletter   alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.ligacoes     alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.meta_semanal alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.meta_mensal  alter column organizacao_id set default %L', uid_org);
  execute format('alter table public.lead_evento  alter column organizacao_id set default %L', uid_org);
end $$;

